     .leftJoin(clients, eq(clientContracts.clientId, clients.id))
     .where(whereClause)
     .orderBy(orderFn)
     .limit(limit + 1);

   const hasMore = rows.length > limit;
   const items = hasMore ? rows.slice(0, limit) : rows;

   const enriched = items.map((row) => ({
     ...row,
     bd: {
       id: row.assigneeId,
       image: row.bdImage,
       name: row.bdName,
