import { format } from "date-fns";
import { Clock } from "lucide-react";

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";

export type AuditLogEntry = {
  changedAt: Date | null;
  changedByName: string | null;
  field: string;
  id: number;
  newValue: string | null;
  oldValue: string | null;
};

type AuditLogsProps = {
  domainName?: string;
  entries: AuditLogEntry[];
};

export default function AuditLogs({ domainName, entries }: AuditLogsProps) {
  if (entries.length === 0) return null;

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Clock className="h-4 w-4" />
          Audit Logs
        </CardTitle>
        {domainName && (
          <CardDescription>
            History of changes made to this {domainName}
          </CardDescription>
        )}
      </CardHeader>
      <CardContent>
        <div className="space-y-3">
          {entries.map((entry) => (
            <div className="flex items-start gap-3" key={entry.id}>
              <div className="mt-1.5 h-2 w-2 shrink-0 rounded-full bg-muted" />
              <div className="min-w-0 flex-1">
                <p className="text-sm">
                  <span className="font-medium">{entry.field}</span>
                  {entry.oldValue && (
                    <span className="text-muted-foreground">
                      {" "}
                      from &ldquo;{entry.oldValue}&rdquo;
                    </span>
                  )}
                  {entry.newValue && (
                    <span className="text-muted-foreground">
                      {" "}
                      to &ldquo;{entry.newValue}&rdquo;
                    </span>
                  )}
                </p>
                <p className="text-muted-foreground text-xs">
                  {entry.changedByName && <span>{entry.changedByName}</span>}
                  {entry.changedByName && entry.changedAt && <span> &middot; </span>}
                  {entry.changedAt &&
                    format(new Date(entry.changedAt), "MMM d, yyyy h:mm a")}
                </p>
              </div>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}

