import { format } from "date-fns";
import { Clock } from "lucide-react";

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";

export type AuditLogEntry = {
  changedAt: Date | null;
  changedByName: string | null;
  field: string;
  id: number;
  newValue: string | null;
  oldValue: string | null;
};

type AuditLogsProps = {
  domainName?: string;
  entries: AuditLogEntry[];
};

function formatRelativeTime(date: Date | null): string {
  if (!date) return "";
  const now = new Date();
  const d = date instanceof Date ? date : new Date(date);
  const diffMs = now.getTime() - d.getTime();
  const diffSec = Math.floor(diffMs / 1000);
  const diffMin = Math.floor(diffSec / 60);
  const diffHr = Math.floor(diffMin / 60);
  const diffDay = Math.floor(diffHr / 24);
  const diffWeek = Math.floor(diffDay / 7);
  const diffMonth = Math.floor(diffDay / 30);
  const diffYear = Math.floor(diffDay / 365);

  if (diffSec < 60) return `${diffSec}s ago`;
  if (diffMin < 60) return `${diffMin}m ago`;
  if (diffHr < 24) return `${diffHr}h ago`;
  if (diffDay < 7) return `${diffDay}d ago`;
  if (diffWeek < 5) return `${diffWeek}w ago`;
  if (diffMonth < 12) return `${diffMonth}mo ago`;
  return `${diffYear}y ago`;
}

export default function AuditLogs({ domainName, entries }: AuditLogsProps) {
  if (entries.length === 0) return null;

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Clock className="h-4 w-4" />
          Audit Logs
        </CardTitle>
        {domainName && (
          <CardDescription>
            History of changes made to this {domainName}
          </CardDescription>
        )}
      </CardHeader>
      <CardContent>
        <div className="space-y-3">
          {entries.map((entry) => (
            <div className="flex items-start gap-3" key={entry.id}>
              <div className="mt-1.5 h-2 w-2 shrink-0 rounded-full bg-muted" />
              <div className="min-w-0 flex-1">
                <p className="text-sm">
                  <span className="font-medium">{entry.field}</span>
                  {entry.oldValue && (
                    <span className="text-muted-foreground">
                      {" "}
                      from &ldquo;{entry.oldValue}&rdquo;
                    </span>
                  )}
                  {entry.newValue && (
                    <span className="text-muted-foreground">
                      {" "}
                      to &ldquo;{entry.newValue}&rdquo;
                    </span>
                  )}
                </p>
                <p className="text-muted-foreground text-xs">
                  {entry.changedByName && <span>{entry.changedByName}</span>}
                  {entry.changedByName && entry.changedAt && (
                    <span> &middot; </span>
                  )}
                  {entry.changedAt && (
                    <TooltipProvider>
                      <Tooltip>
                        <TooltipTrigger className="cursor-default">
                          {formatRelativeTime(entry.changedAt)}
                        </TooltipTrigger>
                        <TooltipContent>
                          {format(new Date(entry.changedAt), "MMM d, yyyy h:mm a")}
                        </TooltipContent>
                      </Tooltip>
                    </TooltipProvider>
                  )}
                </p>
              </div>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}

