import { format } from "date-fns";
import { Clock, MessageSquare, Phone } from "lucide-react";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Popover,
  PopoverContent,
  PopoverHeader,
  PopoverTitle,
  PopoverTrigger,
} from "@/components/ui/popover";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";

export type AuditLogEntry = {
  changedAt: Date | null;
  changedBy: string | null;
  changedByEmail: string | null;
  changedByImage: string | null;
  changedByName: string | null;
  changedByPhone: string | null;
  field: string;
  id: number;
  newValue: string | null;
  oldValue: string | null;
};

type AuditLogsProps = {
  domainName?: string;
  entries: AuditLogEntry[];
};

function formatRelativeTime(date: Date | null): string {
  if (!date) return "";
  const now = new Date();
  const d = date instanceof Date ? date : new Date(date);
  const diffMs = now.getTime() - d.getTime();
  const diffSec = Math.floor(diffMs / 1000);
  const diffMin = Math.floor(diffSec / 60);
  const diffHr = Math.floor(diffMin / 60);
  const diffDay = Math.floor(diffHr / 24);
  const diffWeek = Math.floor(diffDay / 7);
  const diffMonth = Math.floor(diffDay / 30);
  const diffYear = Math.floor(diffDay / 365);

  if (diffSec < 60) return `${diffSec}s ago`;
  if (diffMin < 60) return `${diffMin}m ago`;
  if (diffHr < 24) return `${diffHr}h ago`;
  if (diffDay < 7) return `${diffDay}d ago`;
  if (diffWeek < 5) return `${diffWeek}w ago`;
  if (diffMonth < 12) return `${diffMonth}mo ago`;
  return `${diffYear}y ago`;
}

function stripPlus(phone: string | null): string {
  if (!phone) return "";
  return phone.replace(/[^\d]/g, "");
}

function PersonPopover({ entry }: { entry: AuditLogEntry }) {
  if (!entry.changedByName) return null;

  const phoneStripped = stripPlus(entry.changedByPhone);

  return (
    <Popover>
      <PopoverTrigger className="cursor-default underline decoration-dotted underline-offset-2">
        {entry.changedByName}
      </PopoverTrigger>
      <PopoverContent align="start" side="top" className="w-64">
        <div className="flex items-center gap-3">
          <Avatar className="h-10 w-10">
            <AvatarImage src={entry.changedByImage ?? undefined} />
            <AvatarFallback>
              {entry.changedByName[0]?.toUpperCase() ?? "?"}
            </AvatarFallback>
          </Avatar>
          <PopoverHeader className="min-w-0 flex-1">
            <PopoverTitle className="truncate text-sm">
              {entry.changedByName}
            </PopoverTitle>
            {entry.changedByEmail && (
              <p className="text-muted-foreground truncate text-xs">
                {entry.changedByEmail}
              </p>
            )}
            {entry.changedByPhone && (
              <p className="text-muted-foreground text-xs">
                {entry.changedByPhone}
              </p>
            )}
          </PopoverHeader>
        </div>
        <div className="flex gap-2 pt-2">
          {entry.changedByPhone && (
            <Button asChild size="sm" variant="outline">
              <a href={`tel:${phoneStripped}`}>
                <Phone className="h-3.5 w-3.5" />
                Call
              </a>
            </Button>
          )}
          {phoneStripped && (
            <Button asChild size="sm" variant="outline">
              <a
                href={`https://wa.me/${phoneStripped}`}
                rel="noopener noreferrer"
                target="_blank"
              >
                <MessageSquare className="h-3.5 w-3.5" />
                Message
              </a>
            </Button>
          )}
        </div>
      </PopoverContent>
    </Popover>
  );
}

export default function AuditLogs({ domainName, entries }: AuditLogsProps) {
  if (entries.length === 0) return null;

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Clock className="h-4 w-4" />
          Audit Logs
        </CardTitle>
        {domainName && (
          <CardDescription>
            History of changes made to this {domainName}
          </CardDescription>
        )}
      </CardHeader>
      <CardContent>
        <div className="space-y-3">
          {entries.map((entry) => (
            <div className="flex items-start gap-3" key={entry.id}>
              <div className="mt-1.5 h-2 w-2 shrink-0 rounded-full bg-muted" />
              <div className="min-w-0 flex-1">
                <p className="text-sm">
                  <span className="font-medium">{entry.field}</span>
                  {entry.oldValue && (
                    <span className="text-muted-foreground">
                      {" "}
                      from &ldquo;{entry.oldValue}&rdquo;
                    </span>
                  )}
                  {entry.newValue && (
                    <span className="text-muted-foreground">
                      {" "}
                      to &ldquo;{entry.newValue}&rdquo;
                    </span>
                  )}
                </p>
                <p className="text-muted-foreground text-xs">
                  <PersonPopover entry={entry} />
                  {entry.changedByName && entry.changedAt && (
                    <span> &middot; </span>
                  )}
                  {entry.changedAt && (
                    <TooltipProvider>
                      <Tooltip>
                        <TooltipTrigger className="cursor-default">
                          {formatRelativeTime(entry.changedAt)}
                        </TooltipTrigger>
                        <TooltipContent>
                          {format(
                            new Date(entry.changedAt),
                            "MMM d, yyyy h:mm a",
                          )}
                        </TooltipContent>
                      </Tooltip>
                    </TooltipProvider>
                  )}
                </p>
              </div>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}

